onFilesSelected:
(async () => {
    // 1. Kiểm tra file và Form
    const files = FilePicker_NhapKho.files;
    if (!files || files.length === 0) return;

    // Kiểm tra đã chọn Nhân viên và Mức độ trên Form chưa
    if (!sel_NhanVien.selectedOptionValue || !sel_KhanCap.selectedOptionValue) {
      showAlert("❌ Vui lòng chọn Nhân viên và Mức độ (Khẩn cấp) trên Form trước!", "warning");
      resetWidget('FilePicker_NhapKho', true);
      return;
    }

    const excelData = files[0].data;
    if (!excelData || excelData.length === 0) {
      showAlert("❌ File trống!", "error");
      resetWidget('FilePicker_NhapKho', true);
      return;
    }

    let successCount = 0;
    let errorCount = 0;

    try {
      showAlert("⏳ Đang nhập kho...", "info");

      // 2. Vòng lặp xử lý từng dòng
      for (let i = 0; i < excelData.length; i++) {
        let row = excelData[i];

        // Chỉ kiểm tra Mã vật liệu và Số lượng trong Excel
        if (!row.ma_vat_lieu || !row.so_luong) {
          errorCount++;
          continue; 
        }

        // Đẩy dữ liệu (Lấy Mã NV từ sel_NhanVien và Mức độ từ sel_KhanCap)
        await Action_Import_Row.run({
          ma_vat_lieu: String(row.ma_vat_lieu).trim(),
          ten_vat_lieu: row.ten_vat_lieu || '',
          don_vi: row.don_vi || '',
          quy_cach: row.quy_cach || '',
          vi_tri: row.vi_tri || '',
          so_luong: Number(row.so_luong),
          emp_code: sel_NhanVien.selectedOptionValue, 
          urgency_level: sel_KhanCap.selectedOptionValue 
        });

        successCount++;
      }

      // 3. Thông báo kết quả
      showAlert(`✅ Nhập thành công ${successCount} dòng!`, "success");

      // 4. Load lại các bảng
      await Get_LS_Nhap.run();
      await Get_Inventory_Data.run();
			 await 
Get_Bang_Tool.run();

    } catch (err) {
      showAlert("❌ Lỗi: " + err.message, "error");
    } finally {
      resetWidget('FilePicker_NhapKho', true);
    }
})();
